#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, Q;
        scanf("%d %d %d", &N, &M, &Q);
        int **dp = (int **)malloc(N * sizeof(int *));
        int **count = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            dp[i] = (int *)malloc(M * sizeof(int));
            count[i] = (int *)malloc(M * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                dp[i][j] = 1;
                count[i][j] = 1;
            }
        }
        for (int i = 0; i < Q; i++) {
            int r1, c1, r2, c2;
            scanf("%d %d %d %d", &r1, &c1, &r2, &c2);
            r1--; c1--; r2--; c2--;
            for (int j = r1; j <= r2; j++) {
                for (int k = c1; k <= c2; k++) {
                    if (j > r1 && k > c1) {
                        if (dp[j][k] < dp[j - 1][k - 1] + 1) {
                            dp[j][k] = dp[j - 1][k - 1] + 1;
                            count[j][k] = count[j - 1][k - 1];
                        } else if (dp[j][k] == dp[j - 1][k - 1] + 1) {
                            count[j][k] = (count[j][k] + count[j - 1][k - 1]) % MOD;
                        }
                    }
                }
            }
        }
        int maxLen = 0;
        int maxCount = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (dp[i][j] > maxLen) {
                    maxLen = dp[i][j];
                    maxCount = count[i][j];
                } else if (dp[i][j] == maxLen) {
                    maxCount = (maxCount + count[i][j]) % MOD;
                }
            }
        }
        printf("%d %d\n", maxLen, maxCount);
        for (int i = 0; i < N; i++) {
            free(dp[i]);
            free(count[i]);
        }
        free(dp);
        free(count);
    }
    return 0;
}

